import{_ as a,c as t,o as i,a1 as n}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse(`{"title":"Advanced: Pipeline and Internal Mechanics | AI App Factory Tutorial","description":"Deep dive into AI App Factory's 7-stage pipeline, Sisyphus scheduler, permission security mechanisms, and failure handling strategies. Master context optimization and advanced configuration techniques.","frontmatter":{"title":"Advanced: Pipeline and Internal Mechanics | AI App Factory Tutorial","sidebarTitle":"Advanced: Pipeline","subtitle":"Advanced: Pipeline and Internal Mechanics","description":"Deep dive into AI App Factory's 7-stage pipeline, Sisyphus scheduler, permission security mechanisms, and failure handling strategies. Master context optimization and advanced configuration techniques.","tags":["Pipeline","Scheduler","Security","Failure Handling"],"prerequisite":["start-pipeline-overview"],"order":80},"headers":[],"relativePath":"hyz1992/agent-app-factory/advanced/index.md","filePath":"hyz1992/agent-app-factory/advanced/index.md"}`),r={name:"hyz1992/agent-app-factory/advanced/index.md"};function s(o,e,l,d,c,p){return i(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="advanced-pipeline-and-internal-mechanics" tabindex="-1">Advanced: Pipeline and Internal Mechanics <a class="header-anchor" href="#advanced-pipeline-and-internal-mechanics" aria-label="Permalink to &quot;Advanced: Pipeline and Internal Mechanics&quot;">​</a></h1><p>This chapter provides an in-depth explanation of AI App Factory&#39;s core mechanisms and advanced features, including the detailed working principles of the 7-stage pipeline, Sisyphus scheduler scheduling strategies, permission and security mechanisms, failure handling strategies, and how to optimize context to save token costs.</p><div class="warning custom-block"><p class="custom-block-title">Prerequisites</p><p>Before studying this chapter, please ensure you have completed:</p><ul><li><a href="./../../start/getting-started/">Quick Start</a> and <a href="./../../start/installation/">Installation &amp; Configuration</a></li><li><a href="./../../start/pipeline-overview/">7-Stage Pipeline Overview</a></li><li><a href="./../../platforms/claude-code/">Platform Integration</a> configuration</li></ul></div><h2 id="chapter-contents" tabindex="-1">Chapter Contents <a class="header-anchor" href="#chapter-contents" aria-label="Permalink to &quot;Chapter Contents&quot;">​</a></h2><p>This chapter covers the following topics:</p><h3 id="_7-stage-pipeline-deep-dive" tabindex="-1">7-Stage Pipeline Deep Dive <a class="header-anchor" href="#_7-stage-pipeline-deep-dive" aria-label="Permalink to &quot;7-Stage Pipeline Deep Dive&quot;">​</a></h3><ul><li><p><strong><a href="./stage-bootstrap/">Stage 1: Bootstrap - Structure Product Idea</a></strong></p><ul><li>Learn how to transform vague product ideas into structured documentation</li><li>Understand the input and output formats of the Bootstrap Agent</li></ul></li><li><p><strong><a href="./stage-prd/">Stage 2: PRD - Generate Product Requirements Document</a></strong></p><ul><li>Generate MVP-level PRD, including user stories, feature lists, and non-goals</li><li>Master requirement decomposition and prioritization techniques</li></ul></li><li><p><strong><a href="./stage-ui/">Stage 3: UI - Design Interface and Prototype</a></strong></p><ul><li>Use ui-ux-pro-max skill to design UI structure and previewable prototypes</li><li>Understand interface design workflow and best practices</li></ul></li><li><p><strong><a href="./stage-tech/">Stage 4: Tech - Design Technical Architecture</a></strong></p><ul><li>Design minimal viable technical architecture and Prisma data models</li><li>Master technology selection and architecture design principles</li></ul></li><li><p><strong><a href="./stage-code/">Stage 5: Code - Generate Runnable Code</a></strong></p><ul><li>Generate frontend and backend code, tests, and configurations based on UI Schema and Tech design</li><li>Understand code generation workflow and template system</li></ul></li><li><p><strong><a href="./stage-validation/">Stage 6: Validation - Validate Code Quality</a></strong></p><ul><li>Validate dependency installation, type checking, Prisma schema, and code quality</li><li>Master automated quality checking workflow</li></ul></li><li><p><strong><a href="./stage-preview/">Stage 7: Preview - Generate Deployment Guide</a></strong></p><ul><li>Generate complete running instructions and deployment configurations</li><li>Learn CI/CD integration and Git Hooks configuration</li></ul></li></ul><h3 id="internal-mechanisms" tabindex="-1">Internal Mechanisms <a class="header-anchor" href="#internal-mechanisms" aria-label="Permalink to &quot;Internal Mechanisms&quot;">​</a></h3><ul><li><p><strong><a href="./orchestrator/">Sisyphus Scheduler Deep Dive</a></strong></p><ul><li>Understand how the scheduler coordinates the pipeline, manages state, and executes permission checks</li><li>Master scheduling strategies and state machine principles</li></ul></li><li><p><strong><a href="./context-optimization/">Context Optimization: Per-Session Execution</a></strong></p><ul><li>Learn how to use the <code>factory continue</code> command to save tokens</li><li>Master best practices for creating a new session at each stage</li></ul></li><li><p><strong><a href="./security-permissions/">Permissions and Security Mechanisms</a></strong></p><ul><li>Understand capability boundary matrix, privilege escalation handling, and security check mechanisms</li><li>Master security configuration and permission management</li></ul></li><li><p><strong><a href="./failure-handling/">Failure Handling and Rollback</a></strong></p><ul><li>Learn failure detection, retry mechanisms, rollback strategies, and manual intervention workflows</li><li>Master troubleshooting and recovery techniques</li></ul></li></ul><h2 id="learning-path-recommendations" tabindex="-1">Learning Path Recommendations <a class="header-anchor" href="#learning-path-recommendations" aria-label="Permalink to &quot;Learning Path Recommendations&quot;">​</a></h2><h3 id="recommended-learning-order" tabindex="-1">Recommended Learning Order <a class="header-anchor" href="#recommended-learning-order" aria-label="Permalink to &quot;Recommended Learning Order&quot;">​</a></h3><ol><li><p><strong>Complete the 7-Stage Pipeline First</strong> (in order)</p><ul><li>Bootstrap → PRD → UI → Tech → Code → Validation → Preview</li><li>Each stage has clear inputs and outputs; learning in order builds a complete understanding</li></ul></li><li><p><strong>Then Learn the Scheduler and Context Optimization</strong></p><ul><li>Understand how Sisyphus coordinates these 7 stages</li><li>Learn how to optimize context to save token costs</li></ul></li><li><p><strong>Finally Learn Security and Failure Handling</strong></p><ul><li>Master permission boundaries and security mechanisms</li><li>Understand failure scenarios and response strategies</li></ul></li></ol><h3 id="focus-areas-for-different-roles" tabindex="-1">Focus Areas for Different Roles <a class="header-anchor" href="#focus-areas-for-different-roles" aria-label="Permalink to &quot;Focus Areas for Different Roles&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Role</th><th>Focus Chapters</th></tr></thead><tbody><tr><td><strong>Developer</strong></td><td>Code, Validation, Tech, Orchestrator</td></tr><tr><td><strong>Product Manager</strong></td><td>Bootstrap, PRD, UI, Preview</td></tr><tr><td><strong>Tech Lead</strong></td><td>Tech, Code, Security, Failure Handling</td></tr><tr><td><strong>DevOps Engineer</strong></td><td>Validation, Preview, Context Optimization</td></tr></tbody></table><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this chapter, you can continue learning:</p><ul><li><strong><a href="./../../faq/troubleshooting/">FAQ &amp; Troubleshooting</a></strong> - Resolve issues in actual use</li><li><strong><a href="./../../faq/best-practices/">Best Practices</a></strong> - Master tips for efficient Factory usage</li><li><strong><a href="./../../appendix/cli-commands/">CLI Command Reference</a></strong> - View complete command list</li><li><strong><a href="./../../appendix/code-standards/">Code Standards</a></strong> - Understand standards for generated code</li></ul><hr><p>💡 <strong>Tip</strong>: If you encounter issues during use, please first check the <a href="./../../faq/troubleshooting/">FAQ &amp; Troubleshooting</a> chapter.</p>',19)])])}const g=a(r,[["render",s]]);export{h as __pageData,g as default};
